import React from "react";
import { PageTitle } from '@/components/ui/Typography';
import { PageCard } from "@/components/PageCard";
import { StatusMessage } from "@/components/StatusMessage";
import { BusinessDisplay } from "./BusinessDisplay";
import { CallStatus } from "@/types/api.types";
import { BusinessServices, BusinessServicesError } from "@/api";
import { BusinessResult } from "@/types/business.types";
import { Link } from '@tanstack/react-router';
import { Pathname } from "@/constants/Routes";
import { useInfiniteScroll } from "@/hooks/useInfiniteScroll";
import { InfiniteScrollList } from "@/components/InfiniteScrollList";
import { Box, Button, Typography } from "@mui/material";
import AddIcon from "@mui/icons-material/Add";

const AddBusinessButton: React.FC<{ label?: string }> = ({ label = "Add Business" }) => (
    <Link to={Pathname.Business_Add as string}>
        <Button variant="contained" color="primary" size="small" startIcon={<AddIcon fontSize="small" />} sx={{ textTransform: 'none', borderRadius: 2 }}>
            {label}
        </Button>
    </Link>
);

const TitleWithAdd: React.FC = () => (
    <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
        <PageTitle>My Businesses</PageTitle>
        <AddBusinessButton />
    </Box>
);

export const BusinessView: React.FunctionComponent = () => {
    const {
        items: businesses,
        loading,
        hasMore,
        loadMore,
        error,
        refresh
    } = useInfiniteScroll<BusinessResult>({
        fetchFunction: BusinessServices.GetMyBusinessList,
        initialPageSize: 20,
        autoLoad: true
    });

    const getStatus = (): CallStatus => {
        if (loading && businesses.length === 0) return CallStatus.InProgress;
        if (error) return CallStatus.Failure;
        return CallStatus.Success;
    };

    const status = getStatus();

    if (status !== CallStatus.Success || (status === CallStatus.Success && businesses.length === 0)) {
        return (
            <PageCard>
                <TitleWithAdd />
                {status === CallStatus.Success && businesses.length === 0 ? (
                    <Typography variant="body1">You haven&apos;t added any businesses yet.</Typography>
                ) : (
                    <StatusMessage
                        notStartedMessage="Loading your businesses..."
                        failureMessage={error || BusinessServicesError.GetBusinessesError(0)}
                        currentStatus={status}
                    />
                )}
            </PageCard>
        );
    }

    // Sort businesses by modifiedAt date in descending order (most recent first)
    const sortedBusinesses = [...businesses].sort((a, b) => {
        return new Date(b.modifiedAt ?? 0).getTime() - new Date(a.modifiedAt ?? 0).getTime();
    });

    return (
        <>
            <PageCard>
                <TitleWithAdd />
            </PageCard>
            <InfiniteScrollList
                items={sortedBusinesses}
                renderItem={(business) => (
                    <BusinessDisplay key={business.id} {...business} onDelete={refresh} />
                )}
                loading={loading}
                hasMore={hasMore}
                loadMore={loadMore}
                error={error}
                onRetry={refresh}
                emptyMessage="No businesses found."
            />
        </>
    );
};
