import React from "react";
import { Box } from "@mui/material";
import { Link } from '@tanstack/react-router';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import { Pathname } from "@/constants/Routes";
import { BusinessServices } from "@/api";
import { useBusinessStore } from "@/store";
import { StatusMessage } from "@/components/StatusMessage";
import { CallStatus } from "@/types/api.types";
import { BusinessResult } from "@/types/business.types";
import { BusinessCard } from "@/components/BusinessCard";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { IconActionButton } from "@/components/ui/IconActionButton";
import { logger } from '@/utils/logger';

export const BusinessDisplay = (props: BusinessResult & { onDelete?: () => void }) => {
    const { businessStateList, setBusinessStateList } = useBusinessStore();
    const [confirmDialogOpen, setConfirmDialogOpen] = React.useState(false);
    const [deleteStatus, setDeleteStatus] = React.useState<CallStatus>(CallStatus.NotStarted);
    const [statusMessage, setStatusMessage] = React.useState('');

    const handleDeleteClick = () => {
        setConfirmDialogOpen(true);
    };

    const handleConfirmDelete = async () => {
        if (deleteStatus === CallStatus.InProgress) {
            return;
        }

        setDeleteStatus(CallStatus.InProgress);
        
        try {
            await BusinessServices.DeleteBusiness(props.id);
            // Remove the business from the current state
            const updatedBusinesses = businessStateList.data?.filter(business => business.id !== props.id) || [];
            setBusinessStateList({
                ...businessStateList,
                data: updatedBusinesses
            });
            setStatusMessage(`Business "${props.name}" has been deleted successfully.`);
            setDeleteStatus(CallStatus.Success);
            setConfirmDialogOpen(false);
            if (props.onDelete) props.onDelete();
            // Auto-hide success message after 3 seconds
            setTimeout(() => setDeleteStatus(CallStatus.NotStarted), 3000);
        } catch (error) {
            logger.error('BusinessDisplay', 'Failed to delete business', error);
            setStatusMessage('Failed to delete business. Please try again.');
            setDeleteStatus(CallStatus.Failure);
            // Auto-hide error message after 5 seconds
            setTimeout(() => setDeleteStatus(CallStatus.NotStarted), 5000);
        }
    };

    const handleCancelDelete = () => {
        if (deleteStatus === CallStatus.InProgress) {
            return;
        }
        setConfirmDialogOpen(false);
    };

    return (
        <>
            <StatusMessage
                currentStatus={deleteStatus}
                successMessage={deleteStatus === CallStatus.Success ? statusMessage : undefined}
                failureMessage={deleteStatus === CallStatus.Failure ? statusMessage : undefined}
                style={{ marginBottom: '16px' }}
            />

            <Box>
                <BusinessCard 
                    {...props} 
                    extraActions={
                        <>
                            <IconActionButton tone="error" aria-label="delete" onClick={handleDeleteClick}>
                                <DeleteIcon fontSize="small" />
                            </IconActionButton>
                            <Link to={`${Pathname.Business_Edit}/${props.id}` as string}>
                                <IconActionButton tone="primary" aria-label="edit">
                                    <EditIcon fontSize="small" />
                                </IconActionButton>
                            </Link>
                        </>
                    }
                />
            </Box>

            <ConfirmDialog
                open={confirmDialogOpen}
                onCancel={handleCancelDelete}
                onConfirm={handleConfirmDelete}
                title="Delete Business"
                description={`Are you sure you want to delete "${props.name}"? This action cannot be undone.`}
                confirmLabel="Delete"
                tone="error"
                busy={deleteStatus === CallStatus.InProgress}
                busyLabel="Deleting..."
            />
        </>
    );
};
